class RossumClient:
    def __init__(self, payload: dict) -> None:
        self.base_url = payload["base_url"]
        self.auth_token = payload["rossum_authorization_token"]
        self.headers = self._build_headers()

    def _build_headers(self) -> dict:
        return {"Authorization": f"Bearer {self.auth_token}"}

    def call(self, method: str, endpoint: str, binary: bool = False, **kwargs) -> dict:
        if endpoint.startswith("https://"):
            url = endpoint
        else:
            url = f"{self.base_url}/api/v1/{endpoint}"
        kwargs.setdefault("timeout", DEFAULT_TIMEOUT)
        response = requests.request(method, url, headers=self.headers, **kwargs)
        if not response.ok:
            raise RuntimeError(response.text)

        content_type_json = response.headers.get("Content-Type", "")

        if binary:
            return response.content

        if "application/json" in content_type_json:
            return response.json()

        else:
            return response.content


class ApiClient:
    def __init__(self, rossum) -> None:
        self.rossum: RossumClient = rossum
        self.api_url = f"{rossum.base_url}/api/v1/"

    # ------------------
    # Basic HTTP methods with pagination support
    # ------------------

    def get(self, endpoint: str, id_: str = None, query_params: dict = None):
        url = f"{self.api_url}{endpoint}"
        if id_ is not None:
            if "{id}" in endpoint:
                url = url.format(id=id_)
            else:
                url = f"{url}/{id_}"
        if query_params:
            url = f"{url}?{'&'.join(f'{k}={v}' for k, v in query_params.items())}"

        results = []
        while url:
            response = self.rossum.call("GET", url)
            if isinstance(response, dict) and "results" in response and "pagination" in response:
                results.extend(response.get("results", []))
                url = response.get("pagination", {}).get("next")
            else:
                return response
        return results

    def post(self, endpoint: str, **kwargs):
        url = f"{self.api_url}{endpoint}"
        results = []

        while url:
            response = self.rossum.call("POST", url, **kwargs)
            if isinstance(response, dict) and "results" in response and "pagination" in response:
                results.extend(response.get("results", []))
                url = response.get("pagination", {}).get("next")
            else:
                return response
        return results

    def patch(self, endpoint: str, id_: str, **kwargs):
        return self.rossum.call("PATCH", f"{self.api_url}{endpoint}/{id_}", **kwargs)

    def update_hook_secrets(self, hook_id: str, secrets: dict):
        return self.patch("hooks", id_=hook_id, json={"secrets": secrets})

    def delete(self, endpoint: str, id_: str):
        return self.rossum.call("DELETE", f"{self.api_url}{endpoint}/{id_}", binary=True)

    # ------------------
    # Custom methods
    # ------------------

    def get_relations_parents_attachments(self, parent_id):
        return self.get("relations", query_params={"parent": parent_id, "type": "attachment"})

    def upload_document(self, filename, content, content_type="application/octet-stream"):
        if content_type:
            files = {"content": (filename, content, content_type)}
        else:
            files = {"content": (filename, content)}
        response = self.post("documents", files=files)
        logging.info(f"Uploading document {filename} returned document id {response['id']}\n")
        return response

    def get_existing_relations(self, relation_type, annotation_id, key=None):
        query_params = {"annotation": annotation_id}
        if key is not None:
            query_params["key"] = key
        relations = self.get(relation_type, query_params=query_params)
        return relations

    def create_or_update_relation(self, document, annotation, key):
        existing_relations = self.get_existing_relations("document_relations", annotation["id"], key=key)
        if not existing_relations:
            new_relation = self.post(
                "document_relations",
                json={"documents": [document["url"]], "annotation": annotation["url"], "type": "export", "key": key},
            )
            logging.info(f"Creating new document relation {new_relation['id']}\n")

        else:
            existing_relation = existing_relations[0]
            new_relation = self.patch(
                "document_relations", id_=existing_relation["id"], json={"documents": [document["url"]]}
            )
            logging.info(f"Setting new document into existing document_relation {existing_relation['id']}\n")

            if existing_relation.get("documents"):
                old_document_id = existing_relation["documents"][0].split("/")[-1]
                self.delete("documents", id_=old_document_id)
                logging.info(f"Deleting old document {old_document_id}\n")

        return new_relation


