LOCAL_FILTER_OPERATORS: dict[str, Callable[[Any, Any], bool]] = {
    "$eq": lambda a, b: a == b,
    "$ne": lambda a, b: a != b,
    "$gt": lambda a, b: (a is not None and b is not None and a > b),
    "$gte": lambda a, b: (a is not None and b is not None and a >= b),
    "$lt": lambda a, b: (a is not None and b is not None and a < b),
    "$lte": lambda a, b: (a is not None and b is not None and a <= b),
    "$in": lambda a, b: (b is not None and hasattr(b, "__contains__") and a in b),
    "$nin": lambda a, b: (b is not None and hasattr(b, "__contains__") and a not in b),
    "$regex": lambda a, b: isinstance(a, str) and re.search(b, a) is not None,
    "$exists": lambda a, b: (b and a is not None) or (not b and a is None),
}


RESOLVE_VAR_FUNCTIONS: dict[str, Callable[[Any], Any]] = {
    "base64": lambda v: base64.b64encode(v if isinstance(v, bytes) else str(v).encode("utf-8")).decode("utf-8"),
}


class TokenCache:
    """
    A singleton class to manage and cache authentication tokens.
    """

    _instance = None
    _lock = threading.Lock()

    def __new__(cls):
        if cls._instance is None:
            with cls._lock:
                if cls._instance is None:
                    cls._instance = super(TokenCache, cls).__new__(cls)
        return cls._instance

    @classmethod
    def get_instance(cls):
        """Get the singleton instance."""
        if cls._instance is None:
            cls()  # calls __new__
        return cls._instance

    def _get_config_hash(self, auth_config: "BearerAuth") -> str:
        """Create a stable hash for a given auth configuration."""
        config_json = json.dumps(auth_config.model_dump(), sort_keys=True).encode("utf-8")
        msg_hash = hashlib.sha256(config_json).hexdigest()[:16]

        try:
            hostname = urlparse(auth_config.url).netloc
            safe_hostname = re.sub(r"[^a-zA-Z0-9]", "_", hostname)
            # Ensure the hostname isn't too long to keep the key manageable
            safe_hostname = safe_hostname[:32]
        except Exception:
            safe_hostname = "auth"

        return f"{safe_hostname}_{msg_hash}"

    def _fetch_new_token(self, auth_config: "BearerAuth") -> str:
        """
        Performs the authentication request to get a new token.
        """
        logging.info(f"Fetching new token for {auth_config.url}")

        with requests.Session() as auth_session:
            auth_session.headers.update(auth_config.headers or {})

            request_args = {
                "method": auth_config.method,
                "url": str(auth_config.url),
                "params": auth_config.params,
            }

            if auth_config.content_type == "json":
                request_args["json"] = auth_config.content
            else:
                request_args["data"] = auth_config.content

            try:
                response = auth_session.request(**request_args, timeout=DEFAULT_TIMEOUT)

                if not response.ok:
                    logging.error(f"Auth request failed with {response.status_code}: {response.text}\n")
                    response.raise_for_status()

                auth_data = response.json()
                keys = auth_config.credential_key.split(".")
                token = auth_data
                for key in keys:
                    token = token.get(key)
                    if token is None:
                        logging.error(f"Auth token not found at key '{auth_config.credential_key}'\n")
                        raise ResolveVarError(auth_config.credential_key, "Auth Response")

                logging.info(f"Successfully fetched new token for {auth_config.url}")
                return token

            except (requests.RequestException, JSONDecodeError, ResolveVarError) as e:
                logging.error(f"Failed to fetch or parse auth token: {str(e)}")
                raise

    def get_token(self, auth_config: "BearerAuth", payload: dict, api_client: ApiClient) -> str:
        """
        Get a token from the cache (payload) or fetch a new one and update API.
        """
        config_hash = self._get_config_hash(auth_config)
        secrets = payload.get("secrets") or {}
        cache_key = f"_request_processor_token_cache_{config_hash}"

        if cache_key in secrets:
            logging.info(f"Using cached token from payload for {auth_config.url}")
            return secrets[cache_key]

        token = self._fetch_new_token(auth_config)

        if "secrets" not in payload:
            payload["secrets"] = {}
        payload["secrets"][cache_key] = token

        try:
            hook_id = payload["hook"].split("/")[-1]
            api_client.update_hook_secrets(hook_id, payload["secrets"])
            logging.info(f"Updated secrets on API for hook {hook_id}")
        except Exception as e:
            logging.warning(f"Failed to update secrets on API: {e}")

        return token

    def invalidate_token(self, auth_config: "BearerAuth", payload: dict):
        """
        Remove an expired token from the cache (payload).
        """
        config_hash = self._get_config_hash(auth_config)
        cache_key = f"_request_processor_token_cache_{config_hash}"
        if payload.get("secrets") and cache_key in payload["secrets"]:
            del payload["secrets"][cache_key]
            logging.info(f"Invalidated token in payload for {auth_config.url}")


def resolve_var(expr: str, context: dict, api_client: ApiClient | None = None, raise_exceptions: bool = False) -> Any:
    """
    Resolve a variable expression like 'a[0].b' or 'a["key"]' in the given context dictionary.
    Supports base64 encoding wrapper: 'base64(payload.content)' will resolve the inner expression
    and return its base64-encoded value.
    Args:
        expr (str): The variable expression to resolve.
        context (dict): The context dictionary to look up variables.
        api_client (ApiClient | None): Optional ApiClient to fetch data from URLs.
        raise_exceptions (bool): Whether to raise exceptions on unresolved variables.
    Returns:
        Any: The resolved value, or None if any part of the path is invalid.
    """

    def is_url(url_string: str):
        try:
            if not isinstance(url_string, str):
                return False
            result = urlparse(url_string)
            return result.scheme in ("http", "https") and bool(result.netloc)
        except ValueError:
            return False

    def is_same_origin(url_string: str) -> bool:
        """Check if URL is same origin as api_client base_url.

        Compares the last two parts of the domain (e.g., rossum.ai) to allow
        api.elis.rossum.ai to match elis.rossum.ai.
        """
        if not api_client:
            return False
        try:
            url_host = urlparse(url_string).netloc
            base_host = urlparse(api_client.rossum.base_url).netloc
            url_domain = ".".join(url_host.split(".")[-2:])
            base_domain = ".".join(base_host.split(".")[-2:])
            return url_domain == base_domain
        except Exception:
            return False

    fn_match = re.match(r"^(\w+)\((.+)\)$", expr)
    if fn_match:
        fn_name = fn_match.group(1)
        if fn_name in RESOLVE_VAR_FUNCTIONS:
            inner_expr = fn_match.group(2)
            inner_value = resolve_var(inner_expr, context, api_client, raise_exceptions)
            if inner_value is None:
                return None
            return RESOLVE_VAR_FUNCTIONS[fn_name](inner_value)
        if raise_exceptions:
            raise ResolveVarError(f"Unknown function: {fn_name}", expr)
        return None

    match = re.match(r"^(\w+)", expr)
    if not match:
        return None

    var_name = match.group(1)
    if var_name not in context:
        if raise_exceptions:
            raise ResolveVarError(var_name, expr)
        return None

    value = context[var_name]
    remaining_path = expr[match.end() :]

    while remaining_path:
        # Check for explicit fetch operator .@
        if remaining_path.startswith(".@"):
            if api_client and is_url(value):
                if is_same_origin(value):
                    value = api_client.rossum.call("GET", value)
                else:
                    if raise_exceptions:
                        raise ResolveVarError(value, f"URL fetch not allowed (different origin): {value}")
                    return None
            remaining_path = remaining_path[2:]  # consume ".@"
            continue

        # dot access (e.g., .key)
        dot_match = re.match(r"^\.(\w+)", remaining_path)
        if dot_match:
            key = dot_match.group(1)
            try:
                if isinstance(value, dict):
                    if key in value:
                        value = value[key]
                    else:
                        if raise_exceptions:
                            raise ResolveVarError(key, expr)
                        return None
                else:
                    value = getattr(value, key)

            except (AttributeError, KeyError):
                if raise_exceptions:
                    raise ResolveVarError(key, expr)
                return None  # Failed to get attribute or key

            remaining_path = remaining_path[dot_match.end() :]
            continue

        # bracket access (e.g., [0] or ['key'])
        bracket_match = re.match(r"^\[(.*?)\]", remaining_path)
        if bracket_match:
            accessor_str = bracket_match.group(1)
            try:
                key_or_index = ast.literal_eval(accessor_str)
                value = value[key_or_index]
            except (ValueError, SyntaxError, KeyError, IndexError, TypeError):
                if raise_exceptions:
                    raise ResolveVarError(accessor_str, expr)
                return None

            remaining_path = remaining_path[bracket_match.end() :]
            continue

        # Invalid syntax
        if raise_exceptions:
            raise ResolveVarError(remaining_path, expr)
        return None

    return value


def fill_template(template: dict | list | str, raise_exceptions=False, api_client: ApiClient | None = None, **context):
    """
    Fill in placeholders in a nested dictionary structure using context variables.
    Args:
        template (dict | RelationConfig): The template dictionary with placeholders.
        raise_exceptions (bool): Whether to raise exceptions on unresolved variables.
        api_client (ApiClient | None): The ApiClient to fetch data from URLs.
        **context: Key-value pairs to replace placeholders in the template.
    Returns:
        dict | RelationConfig: A new dictionary with placeholders replaced by context values.
    """

    _placeholder_pattern = re.compile(r"\{([^{}]+)\}")
    _exact_placeholder_pattern = re.compile(r"^\s*\{([^{}]+)\}\s*$")

    def _replace_placeholders(item):
        if isinstance(item, dict):
            new_dict = {}
            for k, v in item.items():
                new_k = _replace_placeholders(k)
                new_v = _replace_placeholders(v)
                new_dict[new_k] = new_v
            return new_dict
        elif isinstance(item, list):
            return [_replace_placeholders(v) for v in item]
        elif isinstance(item, str):
            exact_match = _exact_placeholder_pattern.fullmatch(item)

            if exact_match:
                expr = exact_match.group(1).strip()
                val = resolve_var(expr, context, raise_exceptions=raise_exceptions, api_client=api_client)
                # Return the value directly, with its original type (bytes, int, None, etc.)
                return val

            # If not an exact match, it's a composite string (or a plain string).
            # Perform standard string interpolation.
            def repl(match: re.Match) -> str:
                expr = match.group(1).strip()
                val = resolve_var(expr, context, raise_exceptions=raise_exceptions, api_client=api_client)

                return str(val) if val is not None else ""

            return _placeholder_pattern.sub(repl, item)
        else:
            return item

    return _replace_placeholders(template)


def evaluate_filter(data_list: list[dict], query: dict) -> list[dict]:
    """
    Filters a list of dictionaries using MongoDB-like query syntax.
    Args:
        data_list (list[dict]): A list of dictionaries to filter.
        query (dict): A dictionary representing the filter conditions.
    Returns:
        list[dict]: A new list containing only the items that match the query.
    """

    def _matches(item: dict, sub_query: dict) -> bool:
        # Recursively checks if an item matches a query or sub-query.
        if "$and" in sub_query:
            return all(_matches(item, q) for q in sub_query["$and"])

        if "$or" in sub_query:
            return any(_matches(item, q) for q in sub_query["$or"])

        for field, condition in sub_query.items():
            item_value = resolve_var(field, item)

            if isinstance(condition, dict):
                for operator, value in condition.items():
                    if operator == "$size":
                        if not hasattr(item_value, "__len__"):
                            return False

                        array_size = len(item_value)

                        # Nested operators e.g., {$size: {$gte: 10}}
                        if isinstance(value, dict):
                            for sub_op, sub_val in value.items():
                                if sub_op not in LOCAL_FILTER_OPERATORS or not LOCAL_FILTER_OPERATORS[sub_op](
                                    array_size, sub_val
                                ):
                                    return False
                        # Simple equality e.g., {$size: 3}
                        elif isinstance(value, int):
                            if array_size != value:
                                return False
                        else:
                            # Invalid value for $size operator
                            return False
                    else:
                        if operator not in LOCAL_FILTER_OPERATORS or not LOCAL_FILTER_OPERATORS[operator](
                            item_value, value
                        ):
                            return False
            else:
                if not LOCAL_FILTER_OPERATORS["$eq"](item_value, condition):
                    return False

        return True

    return [item for item in data_list if _matches(item, query)]


