class BaseModel(_BaseModel):
    def fill_template(self, context: dict, raise_exceptions=False, api_client=None):
        for field_name, field_value in self.model_dump().items():
            if isinstance(field_value, (dict, list, str)):
                filled_value = fill_template(
                    field_value, raise_exceptions=raise_exceptions, api_client=api_client, **context
                )
                setattr(self, field_name, filled_value)


class BearerAuth(BaseModel):
    url: str
    method: Literal["GET", "POST", "PUT", "PATCH", "DELETE"]
    content_type: Literal["json", "form"] | None = None
    content: dict[str, Any] | None = None
    headers: dict[str, str] = Field(default_factory=dict)
    params: dict[str, Any] = Field(default_factory=dict)
    credential_key: str


class Requester(BaseModel):
    url: str
    method: Literal["GET", "POST", "PUT", "PATCH", "DELETE"]
    content: Any | None = None
    content_type: Literal["json", "form", "files", "multipart"] | None = None
    headers: dict[str, str] | None = None
    iterate_over: str | None = None
    iteration_item_name: str = "item"
    timeout: int = DEFAULT_TIMEOUT

    def execute(self, session: requests.Session, content_batch) -> requests.Response:
        session.headers.update(self.headers or {})
        params = {"method": self.method, "url": str(self.url)}
        if self.content_type == "json":
            params["json"] = content_batch
        elif self.content_type == "files":
            params["files"] = content_batch
        elif self.content_type == "multipart":
            files = {}
            data = {}
            if isinstance(content_batch, dict):
                for key, value in content_batch.items():
                    if isinstance(value, (list, tuple)):
                        files[key] = value
                    else:
                        data[key] = value
            else:
                files = content_batch

            params["files"] = files
            if data:
                params["data"] = data
        else:
            params["data"] = content_batch
        params["timeout"] = self.timeout
        response = session.request(**params)
        logging.info(f"{self.method} API call to {self.url} returned status code {response.status_code}\n")
        return response


class ValueExtractor(BaseModel):
    """Defines how to extract a value from response using one operator."""

    jmespath: str | None = Field(None, alias="$jmespath")
    xmlpath: str | None = Field(None, alias="$xmlpath")
    regex: str | None = Field(None, alias="$regex")

    def model_post_init(self, __context):
        operators = [self.jmespath, self.xmlpath, self.regex]
        if sum(op is not None for op in operators) != 1:
            raise ValueError("Exactly one operator ($jmespath, $xmlpath, or $regex) must be specified")


class ValueConfig(BaseModel):
    """Maps a context path to an extraction operator. e.g., {"response.body": {"$jmespath": "key"}}"""

    model_config = ConfigDict(extra="forbid")

    context_path: str
    extractor: ValueExtractor

    @model_validator(mode="before")
    @classmethod
    def parse_value_config(cls, data: Any) -> dict:
        if isinstance(data, dict) and "context_path" not in data:
            # Shorthand format: {"response.body": {"$jmespath": "key"}}
            if len(data) != 1:
                raise ValueError("value config must contain exactly one context path")
            context_path, extractor_dict = next(iter(data.items()))
            return {"context_path": context_path, "extractor": extractor_dict}
        return data


class ResponseHandler(BaseModel):
    condition: dict[str, Any] | None = None  # condition to evaluate to decide if this handler is applicable
    target_type: Literal["schema_id", "document_relation", "property"]
    target_key: (
        str  # target schema id to store the response. If not resolvable, store as document relation with this key
    )
    value: ValueConfig | None = None

    def handle_response(
        self,
        api_call: "CallApiPhase",
        response: requests.Response,
        accessible_variables: "AccessibleVariables",
        sequence,
    ) -> bool:
        def response_to_dict(response: requests.Response) -> dict:
            normalized_headers = {k.replace("-", "_").lower(): v for k, v in response.headers.items()}

            return {
                "status_code": response.status_code,
                "headers": normalized_headers,
                "headers_raw": list(response.headers.items()),
                "text": response.text,
                "content": response.content,
                "url": response.url,
                "reason": response.reason,
                "elapsed": response.elapsed.total_seconds(),
                "ok": response.ok,
                "encoding": response.encoding,
                "cookies": dict(response.cookies),
            }

        content_type = response.headers.get("Content-Type", "unknown")
        context = {"response": response_to_dict(response)}
        found_value = None

        # Parse response body based on content type
        match content_type:
            case _ if "application/json" in content_type:
                body = response.json()
                context["response"]["body"] = body
                logging.info(f"Response content type is JSON for call api phase '{api_call.name}'\n")
            case _ if "xml" in content_type:
                xml_tree = ET.fromstring(response.text)
                context["response"]["body"] = response.text
                context["response"]["_xml_tree"] = xml_tree  # Store parsed tree for XPath
                logging.info(f"Response content type is XML for call api phase '{api_call.name}'\n")
            case _ if "text" in content_type:
                context["response"]["body"] = response.text
                logging.info(f"Response content type is Text for call api phase '{api_call.name}'\n")
            case _ if "unknown" in content_type:
                logging.info(f"Response content type is None (no body) for call api phase '{api_call.name}'\n")
            case _:
                body = response.content
                context["response"]["body"] = body
                logging.warning(
                    f"Response content type is unsupported ({content_type}) for call api phase '{api_call.name}'\n"
                )

        # Extract value using configured operator
        if self.value:
            # Get the target data from context
            path_parts = self.value.context_path.split(".")
            target_data = context
            for part in path_parts:
                target_data = target_data.get(part, {})

            # Apply the appropriate operator
            if self.value.extractor.jmespath:
                found_value = jmespath.search(self.value.extractor.jmespath, target_data)
                logging.info(
                    f"Applied JMESPath query '{self.value.extractor.jmespath}' on '{self.value.context_path}'\n"
                )

            elif self.value.extractor.xmlpath:
                if "_xml_tree" not in context["response"]:
                    raise ValueError("$xmlpath operator can only be used with XML responses")
                xml_tree = context["response"]["_xml_tree"]
                try:
                    xpath_result = xml_tree.findall(self.value.extractor.xmlpath)
                    if xpath_result:
                        if len(xpath_result) > 1:
                            found_value = [
                                elem.text if elem.text else ET.tostring(elem, encoding="unicode")
                                for elem in xpath_result
                            ]
                        else:
                            elem = xpath_result[0]
                            found_value = elem.text if elem.text else ET.tostring(elem, encoding="unicode")
                    else:
                        found_value = None
                    logging.info(f"Applied XPath query '{self.value.extractor.xmlpath}' on XML\n")
                except Exception as e:
                    logging.warning(f"XPath query '{self.value.extractor.xmlpath}' failed: {e}\n")
                    found_value = None

            elif self.value.extractor.regex:
                if not isinstance(target_data, str):
                    target_data = str(target_data)
                match_obj = re.search(self.value.extractor.regex, target_data)
                if match_obj:
                    try:
                        found_value = match_obj.group(1)
                    except IndexError:
                        found_value = match_obj.group(0)
                else:
                    found_value = None
                logging.info(f"Applied regex pattern '{self.value.extractor.regex}' on '{self.value.context_path}'\n")

            context["found_value"] = found_value

        if self.condition and check_condition(self.condition, context) is False:
            logging.info(f"Response handler condition not met for call api phase '{api_call.name}'\n")
            return False

        target_key = self.target_key.format(sequence=sequence)
        match self.target_type:
            case "schema_id":
                if isinstance(found_value, dict):
                    found_value = json.dumps(found_value)
                accessible_variables.field_cache[target_key].append(found_value)
                setattr(accessible_variables.field, target_key, found_value)
                return True
            case "property":
                if accessible_variables.property_.get(target_key):
                    logging.warning(
                        f"Variable {found_value} overwritten the property.{target_key}, because you use the same key multiple times. Old value is deleted."
                    )
                accessible_variables.property_[target_key] = found_value
                return True
            case "document_relation":
                api_client: ApiClient = accessible_variables.api_client
                document = api_client.upload_document(f"{target_key}_response", response.text, "text/plain")
                api_client.create_or_update_relation(
                    document, accessible_variables.payload["annotation"], self.target_key
                )
                logging.info(
                    f"Response handling for call api phase '{api_call.name}' stored response as document and created document relation with key '{self.target_key}'\n"
                )
                return True

        return False


class CallApiPhase(BaseModel):
    name: str
    auth: BearerAuth | None = None
    request: Requester
    priority_response_handlers: list[
        ResponseHandler
    ] = []  # list of response handlers to try in order, after first successful one, skip rest
    response_handlers: list[ResponseHandler] = []
    # list of response handlers to always run


class EvaluatePhase(BaseModel):
    name: str  # name of the condition to be evaluated and logged
    condition: dict[str, Any]  # condition to be evaluated


class GetContentPhase(BaseModel):
    name: str  # name of the content to be retrieved and stored in property
    source: Literal[
        "relation",
        "document_relation",
        "explicit",
        "document_relation_content",
        "relation_content",
        "parent_relation",
        "parent_relation_content",
    ]  # source type
    query: dict[str, Any] | list[str]  # rule to get content


class Stage(BaseModel):
    evaluate: list[EvaluatePhase] | None = None  # stage that must evaluate to True...
    get_content: list[GetContentPhase] | None = None  # stage to get content from relations or explicit fields
    call_api: list[CallApiPhase] | None = None  # stage to call external APIs


class Settings(BaseModel):
    stages: list[Stage]
    debugging: bool = False


class AccessibleVariables(BaseModel):
    model_config = ConfigDict(arbitrary_types_allowed=True)

    payload: dict[str, Any]
    field: txscript.fields.Fields
    field_cache: dict = defaultdict(list)
    property_: dict[str, Any] = Field(alias="property")
    api_client: "ApiClient"
    _relations: list[dict[str, Any]] = PrivateAttr(default=None)
    _document_relations: list[dict[str, Any]] = PrivateAttr(default=None)
    _parent_relations: list[dict[str, Any]] = PrivateAttr(default=None)

    @property
    def relations(self) -> list[dict[str, Any]]:
        if self._relations is None:
            self._relations = self.api_client.get_existing_relations(
                relation_type="relations", annotation_id=self.payload["annotation"]["id"]
            )
        return self._relations

    @property
    def document_relations(self) -> list[dict[str, Any]]:
        if self._document_relations is None:
            self._document_relations = self.api_client.get_existing_relations(
                relation_type="document_relations", annotation_id=self.payload["annotation"]["id"]
            )
        return self._document_relations

    @property
    def parent_relations(self) -> list[dict[str, Any]]:
        if self._parent_relations is None:
            current_id = str(self.payload["annotation"]["id"])
            self._parent_relations = self.api_client.get_relations_parents_attachments(
                parent_id=self.payload["annotation"]["id"]
            )
            for parent_relation in self._parent_relations:
                parent_relation["annotations"] = [
                    a for a in parent_relation["annotations"] if not a.endswith(current_id)
                ]
        return self._parent_relations

    @property
    def context(self):
        return {"payload": self.payload, "field": self.field, "property": self.property_}


