def check_condition(condition: dict, data: dict) -> bool:
    filled_filter = fill_template(condition, **data)
    if not evaluate_filter([data], filled_filter):
        return False
    return True


def _enrich_relations_with_documents(relations: list[dict[str, Any]], api_client: "ApiClient") -> list[dict[str, Any]]:
    # Collect all unique annotation URLs across all relations
    all_annotation_urls = {url for relation in relations for url in relation.get("annotations", [])}
    if not all_annotation_urls:
        return []

    # Batch fetch all annotations in one request
    annotation_ids = ",".join(url.rsplit("/", 1)[-1] for url in all_annotation_urls)
    annotations_by_url = {a["url"]: a for a in api_client.get("annotations", query_params={"id": annotation_ids})}

    # Batch fetch all documents in one request
    unique_doc_urls = {a["document"] for a in annotations_by_url.values()}
    document_ids = ",".join(url.rsplit("/", 1)[-1] for url in unique_doc_urls)
    documents_by_url = {d["url"]: d for d in api_client.get("documents", query_params={"id": document_ids})}

    # Build enriched entries (content is a URL, resolved lazily via .@ in templates)
    enriched = []
    for relation in relations:
        for annotation_url in relation.get("annotations", []):
            annotation = annotations_by_url[annotation_url]
            document = documents_by_url[annotation["document"]]
            enriched.append(
                {**relation, "annotation": annotation, "document": document, "content": document["content"]}
            )
    return enriched


def get_content(content_rules: list[GetContentPhase], accessible_variables: AccessibleVariables):
    for rule in content_rules:
        match rule.source:
            case "relation":
                filtered_results = evaluate_filter(accessible_variables.relations, rule.query)
            case "document_relation":
                filtered_results = evaluate_filter(accessible_variables.document_relations, rule.query)
            case "document_relation_content":
                filtered_results = evaluate_filter(accessible_variables.document_relations, rule.query)
                documents = []
                for result in filtered_results:
                    for document_url in result["documents"]:
                        document = accessible_variables.api_client.rossum.call("GET", document_url)
                        documents.append(document)
                filtered_results = documents
            case "relation_content":
                filtered_results = evaluate_filter(accessible_variables.relations, rule.query)
                filtered_results = _enrich_relations_with_documents(filtered_results, accessible_variables.api_client)
            case "parent_relation":
                filtered_results = evaluate_filter(accessible_variables.parent_relations, rule.query)
            case "parent_relation_content":
                filtered_results = evaluate_filter(accessible_variables.parent_relations, rule.query)
                filtered_results = _enrich_relations_with_documents(filtered_results, accessible_variables.api_client)
            case "explicit":
                filtered_results = fill_template(
                    rule.query,
                    raise_exceptions=False,
                    api_client=accessible_variables.api_client,
                    **accessible_variables.context,
                )
            case _:
                logging.error(f"Unknown content source: {rule.source}\n")
                continue

        if len(filtered_results) == 1:
            filtered_results = filtered_results[0]
        accessible_variables.property_[rule.name] = filtered_results


def _log_response(
    response: requests.Response,
    message: str,
    level: Literal["debug", "error"] = "debug",
) -> None:
    try:
        response_body = response.json()
    except Exception:
        response_body = response.text
    if level == "error":
        logging.exception(f"{message}\nFull response: status={response.status_code}, body={response_body}")
    else:
        logging.info(f"[DEBUG] {message}: status={response.status_code}, body={response_body}")


