def rossum_hook_request_handler(payload) -> dict | None:
    if not payload.get("rossum_authorization_token"):
        raise ValueError("Rossum authorization token is required.")

    if payload.get("event") != "annotation_content":
        # fool the txscript that its dealing with supported event
        rossum_client = RossumClient(payload)
        content = rossum_client.call("GET", payload["annotation"]["content"], timeout=20)["content"]
        payload["annotation"]["content"] = content
        payload["event"] = "annotation_content"

    rossum_client = RossumClient(payload)
    api_client = ApiClient(rossum_client)
    token_manager = TokenCache.get_instance()

    settings = Settings(**payload.get("settings", {}))
    exception_occurred = False
    t = TxScript.from_payload(payload)
    accessible_variables = AccessibleVariables(
        payload=payload,
        field=t.field,
        property={},
        api_client=api_client,
    )

    for stage_idx, stage in enumerate(settings.stages):
        # first, evaluate the stage condition
        should_evaluate = True
        if stage.evaluate:
            for condition in stage.evaluate:
                if not check_condition(condition.condition, accessible_variables.context):
                    logging.info(f"Skipping {stage_idx + 1}. stage due to unmet condition: {condition.condition}\n")
                    should_evaluate = False
                    break

        if not should_evaluate:
            continue
        logging.info(f"{stage_idx + 1}. stage went through all conditions successfully.\n")

        # process get_content stage. contents are stored in property in accessible_variables
        if stage.get_content:
            get_content(stage.get_content, accessible_variables)
            logging.info(f"Retrieved content for {stage_idx + 1}. stage\n")

        # process call_api stage
        if stage.call_api:
            for api_call in stage.call_api:
                try:
                    api_call: CallApiPhase
                    request_payloads = []

                    # Process Auth and add token to context
                    token = None
                    if api_call.auth:
                        api_call.auth.fill_template(accessible_variables.context, raise_exceptions=True)
                        token = token_manager.get_token(api_call.auth, accessible_variables.payload, api_client)

                    original_request = api_call.request.model_copy()
                    if api_call.request.iterate_over:
                        items = resolve_var(
                            api_call.request.iterate_over, accessible_variables.context, api_client=api_client
                        )

                        # Handle single item (dict) by wrapping in list
                        if items is not None and not isinstance(items, list):
                            items = [items]

                        if items:
                            # Prevent filling content template with global context, as it likely contains item placeholders
                            content_template = api_call.request.content
                            api_call.request.content = None

                            api_call.request.fill_template(
                                accessible_variables.context | {"token": token},
                                raise_exceptions=True,
                                api_client=api_client,
                            )

                            iter_name = api_call.request.iteration_item_name
                            for idx, item in enumerate(items):
                                # Fill template for this item
                                filled_content = fill_template(
                                    content_template,
                                    raise_exceptions=True,
                                    api_client=api_client,
                                    **accessible_variables.context | {iter_name: item, "sequence": idx, "token": token},
                                )
                                request_payloads.append(filled_content)
                        else:
                            logging.warning(
                                f"iterate_over '{api_call.request.iterate_over}' resolved to None or empty. Skipping API call.\n"
                            )
                    else:
                        api_call.request.fill_template(
                            accessible_variables.context | {"sequence": 0, "token": token},
                            raise_exceptions=True,
                            api_client=api_client,
                        )
                        request_payloads = [api_call.request.content]

                    for content_idx, content_batch in enumerate(request_payloads):
                        try:
                            with requests.Session() as session:
                                response = api_call.request.execute(session, content_batch)

                                if settings.debugging:
                                    _log_response(response, f"API response for '{api_call.name}'", level="debug")

                                # Obtain new token if old one doesn't work anymore
                                if response.status_code == 401 and api_call.auth:
                                    logging.warning(
                                        f"Token expired (401) for {api_call.name}. Invalidating and fetching new token."
                                    )
                                    token_manager.invalidate_token(api_call.auth, accessible_variables.payload)
                                    token = token_manager.get_token(
                                        api_call.auth, accessible_variables.payload, api_client
                                    )

                                    api_call.request = original_request.model_copy()
                                    context_for_fill = accessible_variables.context | {"token": token}

                                    if api_call.request.iterate_over:
                                        context_for_fill.update(
                                            {
                                                api_call.request.iteration_item_name: items[content_idx],
                                                "sequence": content_idx,
                                            }
                                        )
                                    else:
                                        context_for_fill["sequence"] = 0

                                    api_call.request.fill_template(
                                        context_for_fill,
                                        raise_exceptions=True,
                                        api_client=api_client,
                                    )
                                    content_batch = api_call.request.content

                                    # If iterating, regenerate future payloads with new token
                                    if api_call.request.iterate_over and items:
                                        iter_name = api_call.request.iteration_item_name
                                        for i in range(content_idx + 1, len(request_payloads)):
                                            filled = fill_template(
                                                content_template,
                                                raise_exceptions=True,
                                                api_client=api_client,
                                                **accessible_variables.context
                                                | {iter_name: items[i], "sequence": i, "token": token},
                                            )
                                            request_payloads[i] = filled

                                    response = api_call.request.execute(session, content_batch)

                                    if settings.debugging:
                                        _log_response(
                                            response, f"API response (retry) for '{api_call.name}'", level="debug"
                                        )

                                for response_handler_idx, response_handler in enumerate(
                                    api_call.priority_response_handlers
                                ):
                                    try:
                                        logging.info(
                                            f"Starting {response_handler_idx + 1}. priority response handler for {stage_idx + 1}. stage (call_api name='{api_call.name}, target type='{response_handler.target_type}', key='{response_handler.target_key}')"
                                        )
                                        valid_response = response_handler.handle_response(
                                            api_call, response, accessible_variables, content_idx
                                        )
                                        if valid_response:
                                            logging.info(
                                                f"Handled response for {stage_idx + 1}. stage (call_api name='{api_call.name}') with priority handler for target type='{response_handler.target_type}', key='{response_handler.target_key}'\n"
                                            )
                                            break
                                        else:
                                            logging.info(
                                                f"{response_handler_idx + 1}. priority response handler for {stage_idx + 1}. stage did not handle the response successfully. Next handler will be evaluated if present."
                                            )
                                    except Exception as e:
                                        exception_occurred = True
                                        _log_response(
                                            response,
                                            f"Error in priority response handler {response_handler_idx + 1} for '{api_call.name}': {str(e)}",
                                            level="error",
                                        )
                                for response_handler_idx, response_handler in enumerate(api_call.response_handlers):
                                    try:
                                        logging.info(
                                            f"Starting {response_handler_idx + 1}. response handler for {stage_idx + 1}. stage (call_api name='{api_call.name}', target type='{response_handler.target_type}', key='{response_handler.target_key})"
                                        )
                                        response_handler.handle_response(
                                            api_call, response, accessible_variables, content_idx
                                        )
                                        logging.info(
                                            f"Handled response for {stage_idx + 1}. stage (call_api name='{api_call.name}') with handler for target type='{response_handler.target_type}', key='{response_handler.target_key}'\n"
                                        )
                                    except Exception as e:
                                        exception_occurred = True
                                        _log_response(
                                            response,
                                            f"Error in response handler {response_handler_idx + 1} for '{api_call.name}': {str(e)}",
                                            level="error",
                                        )
                        except Exception as e:
                            exception_occurred = True
                            logging.exception(
                                f"Error during request execution for {stage_idx + 1}. stage: '{api_call.name}', content batch {content_idx}: {str(e)}\n"
                            )
                            continue
                except Exception as e:
                    exception_occurred = True
                    logging.exception(f"Error in API call for {stage_idx + 1}. stage: '{api_call.name}': {str(e)}'\n")
                    continue
    for key, values in accessible_variables.field_cache.items():
        if len(values) > 1:
            # we tried to write down multiple values to one field. Instead, we make it a list
            setattr(t.field, key, values)

    if exception_occurred:
        t._messages.append(
            {
                "type": "error",
                "content": "Some exception occurred during during export pipeline - request processor run. Check log for details.",
            }
        )

    response = t.hook_response()
    return response
